# ШАБЛОН 4: Треугольник из символов
# Программа рисует треугольник заданной высоты

print('=== ТРЕУГОЛЬНИК ===')
height = int(input('Введите высоту треугольника: '))

if height > 30:
    height = 30
    print('Высота ограничена 30 для красивого отображения.')

print('\nПрямоугольный треугольник:')
# Внешний цикл по строкам
for i in range(1, height + 1):
    # Внутренний цикл: выводим i звёздочек в строке
    for j in range(i):
        print('*', end='')
    print()

print('\nПеревёрнутый треугольник:')
for i in range(height, 0, -1):
    for j in range(i):
        print('*', end='')
    print()

print('\nПирамида:')
for i in range(1, height + 1):
    for j in range(height - i):
        print(' ', end='')
    for j in range(2 * i - 1):
        print('*', end='')
    print()

