# ШАБЛОН 4: Валидатор пароля с функциями
# Программа проверяет пароль на соответствие требованиям

def check_length(password):
    """Проверяет, что длина пароля не меньше 8 символов."""
    return len(password) >= 8

def check_digit(password):
    """Проверяет, что пароль содержит хотя бы одну цифру."""
    for char in password:
        if char.isdigit():
            return True
    return False

def check_uppercase(password):
    """Проверяет, что пароль содержит хотя бы одну заглавную букву."""
    for char in password:
        if char.isupper():
            return True
    return False

def print_result(name, passed):
    """Выводит результат проверки."""
    if passed:
        print(f'[OK] {name}')
    else:
        print(f'[X] {name}')

def validate_password(password):
    """Проверяет пароль по всем критериям."""
    print('\nРезультаты проверки пароля:')
    has_length = check_length(password)
    print_result('Длина >= 8 символов', has_length)
    has_digit = check_digit(password)
    print_result('Содержит цифру', has_digit)
    has_upper = check_uppercase(password)
    print_result('Содержит заглавную букву', has_upper)

    if has_length and has_digit and has_upper:
        print('\nПароль надёжный!')
    else:
        print('\nПароль недостаточно надёжный!')

print('=== ПРОВЕРКА ПАРОЛЯ ===')
password = input('Введите пароль для проверки: ')
validate_password(password)

