# ШАБЛОН 1: Статистика с return
# Программа вычисляет статистические показатели

def calculate_sum(numbers):
    total = 0
    for num in numbers:
        total += num
    return total

def calculate_average(numbers):
    if len(numbers) == 0:
        return 0
    total = calculate_sum(numbers)
    return total / len(numbers)

def find_max(numbers):
    if len(numbers) == 0:
        return None
    max_num = numbers[0]
    for num in numbers:
        if num > max_num:
            max_num = num
    return max_num

def find_min(numbers):
    if len(numbers) == 0:
        return None
    min_num = numbers[0]
    for num in numbers:
        if num < min_num:
            min_num = num
    return min_num

def get_statistics(numbers):
    return {
        'sum': calculate_sum(numbers),
        'average': calculate_average(numbers),
        'max': find_max(numbers),
        'min': find_min(numbers),
        'count': len(numbers)
    }

nums = [15, 22, 8, 34, 19, 27]
stats = get_statistics(nums)

print('=== СТАТИСТИКА ===')
print(f'Числа: {nums}')
print(f'Сумма: {stats["sum"]}')
print(f'Среднее: {stats["average"]:.2f}')
print(f'Максимум: {stats["max"]}')
print(f'Минимум: {stats["min"]}')
print(f'Количество: {stats["count"]}')

