# ШАБЛОН 5: Анализатор текста с return
# Программа анализирует текст и возвращает статистику

def count_words(text):
    if not text.strip():
        return 0
    words = text.split()
    return len(words)

def count_sentences(text):
    if not text.strip():
        return 0
    count = 0
    for char in text:
        if char in '.!?':
            count += 1
    return count

def find_longest_word(text):
    if not text.strip():
        return None
    words = text.split()
    longest = words[0]
    for word in words:
        if len(word) > len(longest):
            longest = word
    return longest

def find_shortest_word(text):
    if not text.strip():
        return None
    words = text.split()
    shortest = words[0]
    for word in words:
        if len(word) < len(shortest):
            shortest = word
    return shortest

def calculate_readability(text):
    if not text.strip():
        return None, 'Текст пуст'
    word_count = count_words(text)
    sentence_count = count_sentences(text)
    if sentence_count == 0:
        return None, 'Нет предложений'
    words_per_sentence = word_count / sentence_count
    if words_per_sentence < 5:
        return words_per_sentence, 'Очень легко читается'
    if words_per_sentence < 15:
        return words_per_sentence, 'Легко читается'
    if words_per_sentence < 25:
        return words_per_sentence, 'Средняя сложность'
    return words_per_sentence, 'Сложный текст'

print('=== АНАЛИЗАТОР ТЕКСТА ===')
