    return count

def find_longest_word(text):
    if not text.strip():
        return None
    words = text.split()
    longest = words[0]
    for word in words:
        if len(word) > len(longest):
            longest = word
    return longest

def find_shortest_word(text):
    if not text.strip():
        return None
    words = text.split()
    shortest = words[0]
    for word in words:
