    cache = {}

    def wrapper(*args):
        if args in cache:
            print(f'[CACHE HIT] {func.__name__}{args}')
            return cache[args]
        result = func(*args)
        cache[args] = result
        print(f'[CACHE MISS] {func.__name__}{args}')
