def validate(**rules):
    def decorator(func):
        def wrapper(*args, **kwargs):
            errors = []

            for param, rule in rules.items():
                if param in kwargs:
                    value = kwargs[param]

                    if 'type' in rule:
                        expected = rule['type']
                        if not isinstance(value, expected):
                            errors.append(
                                f'{param}: ожидается {expected.__name__}, '
                                f'получен {type(value).__name__}'
                            )

                    if 'min' in rule and isinstance(value, (int, float)):
                        if value < rule['min']:
                            errors.append(
