# TEMPLATE 2: Function factory with caching
# The program creates functions with result caching

def cached(func):
    cache = {}

    def wrapper(*args):
        if args in cache:
            print(f'[CACHE HIT] {func.__name__}{args}')
            return cache[args]
        result = func(*args)
        cache[args] = result
        print(f'[CACHE MISS] {func.__name__}{args}')
        return result

    wrapper.cache = cache
    return wrapper

@cached
def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

