def validate(**rules):
    def decorator(func):
        def wrapper(*args, **kwargs):
            errors = []

            for param, rule in rules.items():
                if param in kwargs:
                    value = kwargs[param]

                    if 'type' in rule:
                        expected = rule['type']
                        if not isinstance(value, expected):
                            errors.append(
                                f'{param}: expected {expected.__name__}'
                            )

                    if 'min' in rule and isinstance(value, (int, float)):
                        if value < rule['min']:
                            errors.append(f'{param}: min {rule["min"]}')

            if errors:
                for error in errors:
                    print(f'  - {error}')
                return None

            return func(*args, **kwargs)
        return wrapper
    return decorator

